{"file_text": "using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt", Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute over sauce.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nCanned tomatoes\nHeavy cream\nGarlic\nGinger\nOnion", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or pan-fry chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomatoes and simmer 15 minutes.\n5. Stir in cream and spices.\n6. Add chicken and simmer 10 more minutes.", AverageRating = 4.8, RatingCount = 24 },
        new Recipe { Id = 3, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef\nTaco shells\nLettuce\nTomato\nCheddar cheese\nSour cream\nTaco seasoning\nOnion", Steps = "1. Brown ground beef with diced onion.\n2. Add taco seasoning and water, simmer 5 minutes.\n3. Warm taco shells in oven.\n4. Fill shells with beef mixture.\n5. Top with lettuce, tomato, cheese, and sour cream.", AverageRating = 4.2, RatingCount = 8 },
        new Recipe { Id = 4, Title = "Pad Thai", Category = "Asian", Ingredients = "Rice noodles\nShrimp or tofu\nEgg\nBean sprouts\nGreen onion\nPeanuts\nLime\nFish sauce\nTamarind paste\nSugar", Steps = "1. Soak rice noodles in warm water 30 minutes.\n2. Make sauce: mix tamarind, fish sauce, and sugar.\n3. Stir-fry shrimp/tofu, set aside.\n4. Scramble egg in wok.\n5. Add noodles and sauce, toss until coated.\n6. Add protein back, top with peanuts, sprouts, and lime.", AverageRating = 4.6, RatingCount = 15 },
        new Recipe { Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract\nPinch of salt", Steps = "1. Preheat oven to 425°F (220°C).\n2. Melt chocolate and butter together.\n3. Whisk eggs and sugar until thick.\n4. Fold chocolate mixture into eggs.\n5. Add flour and salt, mix gently.\n6. Pour into greased ramekins.\n7. Bake 12-14 minutes until edges are set but center jiggles.", AverageRating = 4.9, RatingCount = 30 },
        new Recipe { Id = 6, Title = "Caesar Salad", Category = "Salads", Ingredients = "Romaine lettuce\nParmesan cheese\nCroutons\nCaesar dressing\nLemon juice\nGarlic\nAnchovy paste\nOlive oil", Steps = "1. Wash and chop romaine lettuce.\n2. Make dressing: whisk garlic, anchovy paste, lemon juice, and olive oil.\n3. Toss lettuce with dressing.\n4. Add croutons and shaved Parmesan.\n5. Serve immediately.", AverageRating = 4.0, RatingCount = 6 },
    };

    private readonly List<RecipeCategory> _categories = new()
    {
        new RecipeCategory { Name = "Italian", Description = "Classic Italian comfort food — pasta, pizza, and more", Icon = "🍕" },
        new RecipeCategory { Name = "Indian", Description = "Rich spices and bold flavors from the subcontinent", Icon = "🍛" },
        new RecipeCategory { Name = "Mexican", Description = "Vibrant and zesty dishes full of fresh ingredients", Icon = "🌮" },
        new RecipeCategory { Name = "Asian", Description = "Diverse flavors from across East and Southeast Asia", Icon = "🍜" },
        new RecipeCategory { Name = "Desserts", Description = "Sweet treats and indulgent baked goods", Icon = "🍰" },
        new RecipeCategory { Name = "Salads", Description = "Fresh, healthy, and satisfying greens", Icon = "🥗" },
    };

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }

    public void RateRecipe(int recipeId, int rating)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe != null)
        {
            var totalRating = recipe.AverageRating * recipe.RatingCount;
            recipe.RatingCount++;
            recipe.AverageRating = (totalRating + rating) / recipe.RatingCount;
        }
    }
}
