arguments.new_str:
@page "/"

<PageTitle>RecipeHub - Home</PageTitle>

<div class="container">
    <div class="text-center my-5">
        <h1>🍳 RecipeHub</h1>
        <p class="lead">Discover, share, and rate delicious recipes from around the world.</p>
    </div>

    <h2 class="mb-4">Browse by Category</h2>
    <div class="row">
        @foreach (var category in Categories)
        {
            <div class="col-md-4 mb-4">
                <div class="card h-100">
                    <div class="card-body text-center">
                        <span style="font-size: 3rem;">@category.Icon</span>
                        <h5 class="card-title mt-2">@category.Name</h5>
                        <p class="card-text">@category.Description</p>
                        <a href="/category/@category.Name" class="btn btn-primary">View Recipes</a>
                    </div>
                </div>
            </div>
        }
    </div>
</div>

@code {
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

    private List<RecipeHub.Models.RecipeCategory> Categories { get; set; } = new();

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }
}

