                <div class="col-md-6 mb-4">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text text-muted">
                                ⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                            </p>
                            <a href="/recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
    else
    {
        <p class="text-muted">No recipes found in this category yet.</p>
    }
</div>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
