toolArgs.file_text:
@page "/recipe/{RecipeId:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeHub</PageTitle>

<div class="container my-4">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            @if (Recipe != null)
            {
                <li class="breadcrumb-item"><a href="/category/@Recipe.Category">@Recipe.Category</a></li>
                <li class="breadcrumb-item active">@Recipe.Title</li>
            }
        </ol>
    </nav>

    @if (Recipe != null)
    {
        <h1>@Recipe.Title</h1>
        <p class="text-muted">Category: @Recipe.Category</p>

        <div class="row">
            <div class="col-md-4">
                <div class="card mb-4">
                    <div class="card-header"><strong>Ingredients</strong></div>
                    <ul class="list-group list-group-flush">
                        @foreach (var ingredient in Recipe.Ingredients.Split('\n'))
                        {
                            <li class="list-group-item">@ingredient</li>
                        }
                    </ul>
                </div>
            </div>
            <div class="col-md-8">
                <div class="card mb-4">
                    <div class="card-header"><strong>Instructions</strong></div>
                    <div class="card-body">
                        @foreach (var step in Recipe.Steps.Split('\n'))
                        {
                            <p>@step</p>
                        }
                    </div>
                </div>
            </div>
        </div>

        <div class="card">
            <div class="card-body">
                <h5>Rate this Recipe</h5>
                <p class="text-muted">
                    Current rating: ⭐ @Recipe.AverageRating.ToString("F1") (@Recipe.RatingCount ratings)
                </p>
                <RecipeHub.Components.Shared.StarRating RecipeId="Recipe.Id" />
            </div>
        </div>
    }
    else
    {
        <p class="text-muted">Recipe not found.</p>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeHub.Models.Recipe? Recipe { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetRecipeById(RecipeId);
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<div class="container my-4">
    <h1>Submit a Recipe</h1>
    <p class="text-muted">Share your favorite recipe with the community!</p>

    @if (Submitted)
    {
        <div class="alert alert-success">
            <strong>Thank you!</strong> Your recipe has been submitted successfully.
            <a href="/recipe/@NewRecipeId">View your recipe</a>.
        </div>
    }
    else
    {
        <EditForm Model="FormModel" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" />

            <div class="mb-3">
                <label for="title" class="form-label">Recipe Title</label>
                <InputText id="title" class="form-control" @bind-Value="FormModel.Title" />
                <ValidationMessage For="() => FormModel.Title" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="category" class="form-label">Category</label>
                <InputSelect id="category" class="form-select" @bind-Value="FormModel.Category">
                    <option value="">-- Select a category --</option>
                    @foreach (var cat in Categories)
                    {
                        <option value="@cat.Name">@cat.Name</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => FormModel.Category" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="ingredients" class="form-label">Ingredients (one per line)</label>
                <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="FormModel.Ingredients" />
                <ValidationMessage For="() => FormModel.Ingredients" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="steps" class="form-label">Steps (one per line)</label>
                <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="FormModel.Steps" />
                <ValidationMessage For="() => FormModel.Steps" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-primary">Submit Recipe</button>
        </EditForm>
    }
</div>

@code {
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel FormModel { get; set; } = new();
    private List<RecipeHub.Models.RecipeCategory> Categories { get; set; } = new();
    private bool Submitted { get; set; }
    private int NewRecipeId { get; set; }

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        var recipe = new RecipeHub.Models.Recipe
        {
            Title = FormModel.Title,
            Category = FormModel.Category,
            Ingredients = FormModel.Ingredients,
            Steps = FormModel.Steps,
            AverageRating = 0,
            RatingCount = 0
        };

        RecipeService.AddRecipe(recipe);
        NewRecipeId = recipe.Id;
        Submitted = true;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required")]
        public string Steps { get; set; } = string.Empty;
    }
}

