@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= SelectedRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              style="cursor: pointer; font-size: 1.5rem;">
            @(star <= SelectedRating ? "★" : "☆")
        </span>
    }
    @if (HasRated)
    {
        <span class="ms-2 text-success">Thanks! You rated @SelectedRating star@(SelectedRating != 1 ? "s" : "").</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeHub.Services.RecipeService RecipeService { get; set; } = default!;

    private int SelectedRating { get; set; }
    private bool HasRated { get; set; }

    private void Rate(int rating)
    {
        SelectedRating = rating;
        HasRated = true;
        RecipeService.RateRecipe(RecipeId, rating);
    }
}

